{
  "schema": "brainflow.arg_length_policy.v1",
  "purpose": "Reduce Windows CLI arg-length risk by preferring file-based payloads and short command lines.",
  "rules": [
    "Prefer writing large prompts/payloads to files and pass file paths instead of inline arguments.",
    "Keep single CLI invocations short; split steps when needed.",
    "Avoid embedding JSON blobs in command-line args; reference files instead."
  ],
  "examples": {
    "bad": "tool --payload '{...large json...}'",
    "good": "write payload.json; tool --payload-file payload.json"
  }
}
